{
  "mode": "method",
  "tests": [
    {
      "name": "valid_user_login",
      "input": {
        "username": "validUser",
        "password": "validPassword"
      },
      "output": {
        "status": "success",
        "token": "jwt_token_here"
      },
      "notes": "Tests successful login with valid credentials."
    },
    {
      "name": "invalid_user_login",
      "input": {
        "username": "invalidUser",
        "password": "wrongPassword"
      },
      "output": {
        "status": "error",
        "message": "Invalid username or password."
      },
      "notes": "Tests login failure with invalid credentials."
    },
    {
      "name": "role_creation",
      "input": {
        "roleName": "newRole"
      },
      "output": {
        "status": "success",
        "roleId": "new_role_id"
      },
      "notes": "Tests creation of a new role."
    },
    {
      "name": "duplicate_role_creation",
      "input": {
        "roleName": "existingRole"
      },
      "output": {
        "status": "error",
        "message": "Role already exists."
      },
      "notes": "Tests creation failure when role already exists."
    },
    {
      "name": "user_profile_update",
      "input": {
        "userId": "user_id_here",
        "profileData": {
          "email": "newemail@example.com",
          "name": "New Name"
        }
      },
      "output": {
        "status": "success",
        "message": "Profile updated successfully."
      },
      "notes": "Tests successful update of user profile."
    },
    {
      "name": "user_profile_update_invalid_email",
      "input": {
        "userId": "user_id_here",
        "profileData": {
          "email": "invalid_email",
          "name": "New Name"
        }
      },
      "output": {
        "status": "error",
        "message": "Invalid email format."
      },
      "notes": "Tests profile update failure with invalid email."
    },
    {
      "name": "get_user_roles",
      "input": {
        "userId": "user_id_here"
      },
      "output": {
        "status": "success",
        "roles": ["role1", "role2"]
      },
      "notes": "Tests retrieval of roles for a user."
    },
    {
      "name": "get_user_roles_nonexistent_user",
      "input": {
        "userId": "nonexistent_user_id"
      },
      "output": {
        "status": "error",
        "message": "User not found."
      },
      "notes": "Tests retrieval failure for a nonexistent user."
    }
  ],
  "assumptions": "All user and role data is stored in the database and accessible.",
  "notes": "Ensure that the database is in a known state before running tests."
}
